  render: () => <List aria-label="list" sx={{
    width: '100%'
  }}>
      <ListItemStatusCard disablePadding color="warning" secondaryAction={<>
            <IconButton title="Attachments" size="medium">
              <AttachmentIcon fontSize="xsmall" />
            </IconButton>
            <IconButton title="More Actions" size="medium">
              <MoreVerticalIcon fontSize="xsmall" />
            </IconButton>
          </>}>
        <ListItemButton>
          <ListItemText primary="Item" />
          <StatusChip color="warning" label="Pending" />
        </ListItemButton>
      </ListItemStatusCard>
      <ListItemStatusCard disablePadding color="error" secondaryAction={<>
            <IconButton title="Attachments" size="medium">
              <AttachmentIcon fontSize="xsmall" />
            </IconButton>
            <IconButton title="More Actions" size="medium">
              <MoreVerticalIcon fontSize="xsmall" />
            </IconButton>
          </>}>
        <ListItemButton className="Mui-focusVisible">
          <ListItemText primary="Focused Item" />
          <StatusChip color="error" label="Denied" />
        </ListItemButton>
      </ListItemStatusCard>
      <ListItemStatusCard disablePadding color="success" secondaryAction={<IconButton title="More Actions" size="medium">
            <MoreVerticalIcon fontSize="xsmall" />
          </IconButton>}>
        <ListItemButton selected>
          <ListItemText disableTypography primary="Selected Item" />
          <StatusChip color="success" label="Approved" />
        </ListItemButton>
      </ListItemStatusCard>
      <ListItemStatusCard disablePadding color="success" secondaryAction={<IconButton title="More Actions">
            <MoreVerticalIcon fontSize="xsmall" />
          </IconButton>}>
        <ListItemButton>
          <ListItemText>
            Item with long text
            <Typography variant="body2">
              long text
              <br />
              long text
              <br />
              long text
            </Typography>
          </ListItemText>
          <StatusChip color="success" label="Approved" />
        </ListItemButton>
      </ListItemStatusCard>
    </List>
